// soStatusBadgeClass returns a Tailwind badge class for a SalesOrderStatus.
func soStatusBadgeClass(s models.SalesOrderStatus) string {
	switch s {
	case models.SalesOrderStatusDraft:
		return "inline-flex items-center rounded-full bg-muted-soft px-2.5 py-0.5 text-small font-medium text-text-muted"
	case models.SalesOrderStatusConfirmed:
		return "inline-flex items-center rounded-full bg-success-soft px-2.5 py-0.5 text-small font-medium text-success-hover"
	case models.SalesOrderStatusPartiallyInvoiced:
		return "inline-flex items-center rounded-full bg-warning-soft px-2.5 py-0.5 text-small font-medium text-warning-hover"
	case models.SalesOrderStatusFullyInvoiced:
		return "inline-flex items-center rounded-full bg-primary-soft px-2.5 py-0.5 text-small font-medium text-primary"
	case models.SalesOrderStatusCancelled:
		return "inline-flex items-center rounded-full bg-muted-soft px-2.5 py-0.5 text-small font-medium text-text-muted2"
	default:
		return "inline-flex items-center rounded-full bg-muted-soft px-2.5 py-0.5 text-small font-medium text-text-muted"
	}
}

